final:
module RefModule(regA, regB, Wdat,regW, RegWrite, clk, resetn, Adat, Bdat,regTEST,TESTdat);input clk,RegWrite,resetn;		
    input [4:0] regA, regB, regW,regTEST;	
    input [31:0] Wdat;			
    output wire [31:0] Adat, Bdat,TESTdat;		
	 reg [31:0] unused_regfile [0:31];
	 reg [5:0] i;
	 assign  Adat=unused_regfile[regA];
	 assign  Bdat=unused_regfile[regB];
	 assign  TESTdat=unused_regfile[regTEST];

	 always @(posedge clk) begin

		  if (~resetn) for (i=0;i<32;i=i+1) unused_regfile[i]=0; else
		if(RegWrite) unused_regfile[regW]=(regW==0)?32'b0:Wdat;
	end
endmodule
